    param(
        [Parameter(Mandatory)]
        [object[]]$Results
    )

    $byTest = $Results | Group-Object -Property { "{0}::{1}" -f $_.ClassName, $_.Name }

    foreach ($group in $byTest) {
        $passedRuns = @(
            $group.Group | Where-Object Status -EQ 'Passed' |
                Select-Object -ExpandProperty Run
